const n=document.getElementById("nav-toggle"),s=document.getElementById("mobile-menu");n?.addEventListener("click",()=>{const e=!s?.classList.contains("hidden");s?.classList.toggle("hidden"),n.setAttribute("aria-expanded",String(!e));const t=n.querySelector(".material-symbols-outlined");t&&(t.textContent=e?"menu":"close")});const o=new IntersectionObserver(e=>{e.forEach(t=>{t.isIntersecting&&(t.target.classList.add("is-visible"),o.unobserve(t.target))})},{threshold:.12,rootMargin:"0px 0px -40px 0px"});document.querySelectorAll(".fade-in-section").forEach(e=>o.observe(e));
